WITH FemalePatients AS (
  SELECT patient_id, histological_type
  FROM clinical_info
  WHERE histological_type IS NOT NULL AND TRIM(histological_type) <> '' AND "Patient_description" ILIKE '%female%'
)
SELECT * FROM FemalePatients LIMIT 10;

